# Topological Sort Unit Tests

```python
import pytest
from topological_sort import topological_sort


# ---------------------------------------------------------------------------
# Helper
# ---------------------------------------------------------------------------

def is_valid_topological_order(graph: dict, order: list) -> bool:
    """Return True if *order* respects every directed edge in *graph*."""
    position = {node: idx for idx, node in enumerate(order)}
    for node, neighbors in graph.items():
        for neighbor in neighbors:
            if position.get(node, -1) >= position.get(neighbor, len(order)):
                return False
    return True


# ---------------------------------------------------------------------------
# Happy-path tests
# ---------------------------------------------------------------------------

class TestHappyPath:
    def test_simple_linear_chain(self):
        # A -> B -> C  =>  [A, B, C]
        graph = {"A": ["B"], "B": ["C"], "C": []}
        order = topological_sort(graph)
        assert order == ["A", "B", "C"]

    def test_single_node_no_edges(self):
        graph = {"A": []}
        assert topological_sort(graph) == ["A"]

    def test_two_independent_nodes(self):
        graph = {"A": [], "B": []}
        order = topological_sort(graph)
        assert set(order) == {"A", "B"}
        assert len(order) == 2

    def test_diamond_dependency(self):
        #   A
        #  / \
        # B   C
        #  \ /
        #   D
        graph = {"A": ["B", "C"], "B": ["D"], "C": ["D"], "D": []}
        order = topological_sort(graph)
        assert is_valid_topological_order(graph, order)
        assert len(order) == 4

    def test_multiple_roots(self):
        graph = {"A": ["C"], "B": ["C"], "C": []}
        order = topological_sort(graph)
        assert is_valid_topological_order(graph, order)
        assert order[-1] == "C"

    def test_integer_nodes(self):
        graph = {1: [2, 3], 2: [4], 3: [4], 4: []}
        order = topological_sort(graph)
        assert is_valid_topological_order(graph, order)
        assert order[0] == 1
        assert order[-1] == 4

    def test_wide_graph_all_point_to_one_sink(self):
        graph = {f"n{i}": ["sink"] for i in range(5)}
        graph["sink"] = []
        order = topological_sort(graph)
        assert is_valid_topological_order(graph, order)
        assert order[-1] == "sink"

    def test_long_chain_preserves_order(self):
        nodes = list(range(10))
        graph = {nodes[i]: [nodes[i + 1]] for i in range(len(nodes) - 1)}
        graph[nodes[-1]] = []
        order = topological_sort(graph)
        assert order == nodes

    def test_returns_list(self):
        graph = {"X": ["Y"], "Y": []}
        assert isinstance(topological_sort(graph), list)

    def test_all_nodes_present_in_result(self):
        graph = {"A": ["B", "C"], "B": ["D"], "C": [], "D": []}
        order = topological_sort(graph)
        assert set(order) == set(graph.keys())

    def test_no_duplicate_nodes_in_result(self):
        graph = {"A": ["B", "C"], "B": ["D"], "C": ["D"], "D": []}
        order = topological_sort(graph)
        assert len(order) == len(set(order))


